               if( bOutFile )
               {
                  nBytesWritten += ( ULONG ) fwrite( dststr, sizeof( BYTE ), dstlen, outFile );
               }

               hb_xfree( dststr );
            }
         }
      }

      fclose( inFile );

      if( szFileName )
      {
         hb_xfree( szFileName );
      }
   }

   hb_retnl( nBytesWritten );

   hb_xfree( string );

   fclose( outFile );

