void PCodeAnalizer( const HB_BYTE * pCode )
{
   while( * pCode != HB_P_ENDPROC )
   {
      switch( * pCode )
      {
         case HB_P_STATICS:   
              OutputDebugString( "HB_P_STATICS\n" );
              OutputDebugString( BToStr( HB_PCODE_MKUSHORT( &pCode[ 3 ] ) ) );
              OutputDebugString( "\n" );
              pCode += 5;
              break;

         case HB_P_SFRAME:     
              OutputDebugString( "HB_P_SFRAME \n" );
              pCode += 3;
              break;

         case HB_P_PUSHSTRSHORT:     
              OutputDebugString( "HB_P_PUSHSTRSHORT \n" );
              pCode += 2 + pCode[ 1 ];
              break;

         case HB_P_ARRAYGEN:    
              OutputDebugString( "HB_P_ARRAYGEN \n" );
              pCode += 3;
              break; 

         case HB_P_POPSTATIC:     
              OutputDebugString( "HB_P_POPSTATIC \n" );
              pCode += 3;
              break;

         case HB_P_PUSHBYTE: 
              OutputDebugString( "HB_P_PUSHBYTE \n" );
              pCode += 2;
              break;    

         case HB_P_TRUE:     
              OutputDebugString( "HB_P_TRUE \n" );
              pCode++;
              break;    

         case HB_P_FALSE:     
              OutputDebugString( "HB_P_FALSE \n" );
              pCode++;
              break;    

         case HB_P_ZERO:     
              OutputDebugString( "HB_P_ZERO \n" );
              pCode++;
              break;    

         case HB_P_PUSHNIL:     
