              OutputDebugString( "HB_P_POPMEMVAR \n" );
              pCode += 3;
              break;   

         case HB_P_LINE:     
              OutputDebugString( "HB_P_LINE \n" );
              pCode += 3;
              break;   

         case HB_P_FUNCTIONSHORT:     
              OutputDebugString( "HB_P_FUNCTIONSHORT \n" );
              pCode += 2;
              break;   

         case HB_P_RETVALUE:     
              OutputDebugString( "HB_RETVALUE \n" );
              pCode++;
              break;   

         case HB_P_PUSHSTATIC:     
              OutputDebugString( "HB_P_PUSHSTATIC \n" );
              pCode += 3;
              break;   

         case HB_P_JUMPFALSENEAR:     
              OutputDebugString( "HB_P_JUMPFALSENEAR \n" );
              // if( ! hb_vmPopLogical() )
                 pCode += ( signed char ) pCode[ 1 ];
