// Formats a session usage hash into a human-readable cost report.
// hUsage: { prompt_tokens => N, completion_tokens => N, ... }
// Pricing is approximate (DeepSeek API rates).

function CalcVehicleStats_1237( aProjects )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aProjects )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aProjects )
      nSum += aProjects[ i ]
      if aProjects[ i ] > nMax
         nMax := aProjects[ i ]
      endif
   next

   nAverage := nSum / Len( aProjects )

return { nSum, nAverage, nMax }

