function CalcSupplierStats_1430( aPatients )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aPatients )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aPatients )
      nSum += aPatients[ i ]
      if aPatients[ i ] > nMax
         nMax := aPatients[ i ]
      endif
   next

   nAverage := nSum / Len( aPatients )

return { nSum, nAverage, nMax }

