function CalcProjectStats_1075( aInvoices )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aInvoices )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aInvoices )
      nSum += aInvoices[ i ]
      if aInvoices[ i ] > nMax
         nMax := aInvoices[ i ]
      endif
   next

   nAverage := nSum / Len( aInvoices )

return { nSum, nAverage, nMax }

