function CalcVehicleStats_1490( aEmployees )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aEmployees )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aEmployees )
      nSum += aEmployees[ i ]
      if aEmployees[ i ] > nMax
         nMax := aEmployees[ i ]
      endif
   next

   nAverage := nSum / Len( aEmployees )

return { nSum, nAverage, nMax }

