function CalcBookStats_1308( aMembers )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aMembers )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aMembers )
      nSum += aMembers[ i ]
      if aMembers[ i ] > nMax
         nMax := aMembers[ i ]
      endif
   next

   nAverage := nSum / Len( aMembers )

return { nSum, nAverage, nMax }

