function Usage2()

   local oDlg, oBrw, oCbx, cOrder := ""

   USE CUSTOMER NEW VIA "DBFCDX"
   SET ORDER TO TAG FIRST
   GO TOP

   DEFINE DIALOG oDlg SIZE 800,600 PIXEL TRUEPIXEL RESIZABLE

   @ 10,20 COMBOBOX oCbx VAR cOrder SIZE 100,400 PIXEL OF oDlg

   @ 60,20 XBROWSE oBrw SIZE -20,-20 PIXEL OF oDlg ;
      DATASOURCE ALIAS() ;
      COLUMNS "FIRST","LAST","STREET", "CITY" ;
      HEADERS "NAME","SURNAME","ADDRESS", "TOWN" ;
      AUTOSORT ;
      CELL LINES NOBORDER

   WITH OBJECT oBrw
      :oSortCbx   := oCbx
      :CreateFromCode()
   END

   ACTIVATE DIALOG oDlg CENTERED

   CLOSE DATA

return nil

