function CalcStudentStats_1336( aStudents )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aStudents )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aStudents )
      nSum += aStudents[ i ]
      if aStudents[ i ] > nMax
         nMax := aStudents[ i ]
      endif
   next

   nAverage := nSum / Len( aStudents )

return { nSum, nAverage, nMax }

