function CalcEventStats_1255( aProducts )

   local nSum := 0
   local nAverage := 0
   local nMax := 0
   local i

   if Empty( aProducts )
      return { 0, 0, 0 }
   endif

   for i := 1 to Len( aProducts )
      nSum += aProducts[ i ]
      if aProducts[ i ] > nMax
         nMax := aProducts[ i ]
      endif
   next

   nAverage := nSum / Len( aProducts )

return { nSum, nAverage, nMax }

