HB_FUNC( AAT ) // ( acSearch, cTarget ) --> nPosition
{

   WORD wId, wChar;
   WORD wLen = ( WORD ) hb_parinfa( 1, 0 );

   LPSTR szSearch;
   LPSTR szTarget = ( LPSTR ) hb_parc( 2 );

   WORD wLenSearch;
   WORD wLenTarget;

   BOOL bFound = FALSE;
   BOOL bExact;

   int nP = 0;

   wLenTarget = ( WORD ) strlen( szTarget );

   while( *szTarget && !bFound )
   {
      for( wId = 0; ( wId < wLen && !bFound ); wId++ )
      {
         #ifdef __XPP__
            #define hb_parc( x, y ) PARC( x, params, y )
         #endif

         szSearch = ( LPSTR ) hb_parvc( 1, wId + 1 );

         wLenSearch = ( WORD ) strlen( szSearch );

         bExact = TRUE;

         if ( wLenSearch > wLenTarget  )
            bExact = FALSE;
         else
            for ( wChar = 0; ( wChar < wLenSearch && bExact ); wChar++ )
                bExact = ( *( szSearch + wChar ) == *( szTarget + wChar ) );

         bFound = bExact;

      }
      szTarget++;

      nP++;
   }

   hb_retni( IF( bFound, nP, 0 ) );
}
